     else if (req_bit6)

before_code:
module priority_encoder_8 (
  input req_bit0,
  input req_bit1,
  input req_bit2,
  input req_bit3,
  input req_bit4,
  input req_bit5,
  input req_bit6,
  input req_bit7,
  output reg [2:0] priority
);

  always @(req_bit0) begin
    if (req_bit7)
      priority = 3'b111;
    else if (req_bit6)
      priority = 3'b110;
    else if (req_bit5)
      priority = 3'b101;
    else if (req_bit4)
      priority = 3'b100;
    else if (req_bit3)
      priority = 3'b011;
    else if (req_bit2)
      priority = 3'b010;
    else if (req_bit1)
      priority = 3'b001;
    else
      priority = 3'b000;
  end

endmodule

after_code:
module priority_encoder_8 (
  input req_bit0,
  input req_bit1,
  input req_bit2,
  input req_bit3,
  input req_bit4,
  input req_bit5,
  input req_bit6,
  input req_bit7,
  output reg [2:0] priority
);

  always @(req_bit0 or req_bit1 or req_bit2 or req_bit3 or req_bit4 or req_bit5 or req_bit6 or req_bit7) begin
    if (req_bit7)
      priority = 3'b111;
    else if (req_bit6)
      priority = 3'b110;
    else if (req_bit5)
      priority = 3'b101;
    else if (req_bit4)
      priority = 3'b100;
    else if (req_bit3)
      priority = 3'b011;
    else if (req_bit2)
      priority = 3'b010;
    else if (req_bit1)
      priority = 3'b001;
    else
      priority = 3'b000;
  end

endmodule
